package gofile

import (
	"slices"
	"text/template"

	"github.com/zarldev/goenums/enum"
)

type generatedComment struct {
	Version        string
	Command        string
	SourceFilename string
}

var (
	generatedCommentStr = `
// Code generated by goenums {{.Version}}; DO NOT EDIT.
//
// github.com/zarldev/goenums
//
// using the command:
// {{ .Command }}
	`
	generatedCommentTemplate = template.Must(
		template.New("generatedComment").Parse(generatedCommentStr))
)

func (g *Writer) writeGeneratedComments(rep enum.GenerationRequest) {
	g.writeTemplate(generatedCommentTemplate, generatedComment{
		Version:        rep.Version,
		Command:        rep.Command(),
		SourceFilename: rep.SourceFilename,
	})
}

type packageImport struct {
	PackageName     string
	Imports         []string
	ExternalImports []string
}

var (
	packageImportStr = `
package {{ .PackageName }}

import (
{{- range .Imports }}
	"{{ . }}"
{{- end }}
{{ if .ExternalImports }}
{{ range .ExternalImports }}
	"{{ . }}"
{{ end }}
{{ end }}
	)
`
	packageImportTemplate = template.Must(template.New("packageImport").Parse(packageImportStr))
)

func (g *Writer) writePackageAndImports(rep enum.GenerationRequest) {
	importsSet := map[string]struct{}{
		"fmt":  {},
		"math": {},
	}
	for _, path := range rep.Imports {
		importsSet[path] = struct{}{}
	}
	if !rep.Configuration.Legacy {
		importsSet["iter"] = struct{}{}
	}
	if rep.Configuration.Failfast {
		importsSet["errors"] = struct{}{}
	}
	if rep.Configuration.Insensitive {
		importsSet["strings"] = struct{}{}
	}
	if rep.Configuration.Handlers.JSON {
		importsSet["encoding/json"] = struct{}{}
	}
	if rep.Configuration.Handlers.SQL {
		importsSet["database/sql/driver"] = struct{}{}
	}
	if !rep.Configuration.Constraints {
		importsSet["golang.org/x/exp/constraints"] = struct{}{}
	} else {
		delete(importsSet, "golang.org/x/exp/constraints")
	}

	imports := make([]string, 0, len(importsSet))
	for path := range importsSet {
		imports = append(imports, path)
	}
	slices.Sort(imports)
	g.writeTemplate(packageImportTemplate, packageImport{
		PackageName: rep.Package,
		Imports:     imports,
	})
}
